#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Parallelise over the outer dimension – each iteration is independent.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Access the i‑th row of C in a contiguous way
        double* c_row = C[i].data();

        // Step 1: scale the lower triangle of C by beta
        for (int j = 0; j <= i; ++j) {
            c_row[j] *= beta;
        }

        // step 2: accumulate the rank‑1 updates
        for (int k = 0; k < m; ++k) {
            double aik = A[i][k];
            // we need A[j][k] for j <= i – this is read‐only, so we can use a pointer
            for (int j = 0; j <= i; ++j) {
                c_row[j] += alpha * aik * A[j][k];
            }
        }
    }
}
