/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B)
{
    const double inv3 = 1.0/3.0;
    /* We need raw pointers to avoid the cost of bounds checks in the inner loops. */
    double *a = A.data();
    double *b = B.data();

    /* Each time step consists of two independent stencil passes that can be
       parallelised across the eight CPU cores. */
    for (int t = 0; t < tsteps; ++t) {
        /* First pass: compute B from A.  i runs from 1 to n-2 inclusive. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second pass: compute A from B. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
