void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {

    // Parallel over the outer dimension (rows of C).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // pointers to the current row of A, B, and C
        const double* a_row = A[i].data();
        double*               c_row = C[i].data();

        // Scale C[i][*] by beta
        #pragma omp simd
        for (int j = 0; j < nj; ++j) {
            c_row[j] *= beta;
        }

        // Compute contributions from each k
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * a_row[k];
            const double* b_row = B[k].data();

            // SIMD update of C[i][j] += aik * B[k][j]
            #pragma omp simd
            for (int j = 0; j < nj; ++j) {
                c_row[j] += aik * b_row[j];
            }
        }
    }
}
