/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    /* ---------- argument checks (optional) ---------- */
    if (m <= 0 || n <= 0) return;

    /* ---------- reset y (parallel) ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        y[j] = 0.0;

    /* ---------- main kernel ---------- */
    #pragma omp parallel for schedule(dynamic,64) // small block size for good load balance
    for (int i = 0; i < m; ++i)
    {
        /* --------- local variables for this row --------- */
        double* Arow = const_cast<double*>(A[i].data());   // A[i][j]
        double  sum  = 0.0;

        /* ---------- compute tmp[i] = A[i,:] * x ---------- */
        for (int j = 0; j < n; ++j)
            sum += Arow[j] * x[j];

        tmp[i] = sum;

        /* ---------- accumulate into y ---------- */
        for (int j = 0; j < n; ++j)
            y[j] += Arow[j] * sum;
    }
}
