/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b) {
    // Forward substitution: x = L^{-1} b
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        double *Lrow = const_cast<double*>(L[i].data());

        // Evaluate dot product of the i‑th row of L with the already‑computed part of x.
        // `#pragma omp simd` allows compiler‑generated vectorization of the inner loop.
        #pragma omp simd reduction(-:sum)
        for (int j = 0; j < i; ++j)
            sum -= Lrow[j] * x[j];

        // Divide by the diagonal element of L.
        x[i] = sum / Lrow[i];
    }
}
