void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D structure to a 1‑D array for better cache behaviour
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = path[i][j];

    // Main algorithm – parallelised over the outer i loop
    for (int k = 0; k < n; ++k) {
        const int k_off = k * n;                     // pre‑compute for speed
        const int* row_k = flat.data() + k_off;       // row k

        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int* row_i = flat.data() + i * n;           // row i
            const int* row_i_k = row_i + k;            // element (i, k)

            for (int j = 0; j < n; ++j) {
                int cand = *row_i_k + row_k[j];
                if (cand < row_i[j])
                    row_i[j] = cand;
            }
        }
    }

    // Copy result back to the original 2‑D vector
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            path[i][j] = flat[i * n + j];
}
