/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* Parallelise over the outermost loop (rows of B).
       The inner two loops are strictly sequential because each
       B[i][j] depends on all subsequent rows k > i. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Pointers to the start of each row for faster access
        double* Bi = B[i].data();
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            for (int k = i + 1; k < m; ++k) {
                /* A is stored column‑wise by the original index
                   A[k][i] -> the element in row k, column i of A.
                   It is equivalent to (A^T)[i][k], the element used
                   in the mathematical formulation. */
                sum += A[k][i] * B[k][j];
            }
            Bi[j] = alpha * (B[i][j] + sum);
        }
    }
}
