void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    const double coeff = 0.2;
    // Prepare raw pointers for fast row access
    std::vector<double*> rowsA(n), rowsB(n);
    for (int i = 0; i < n; ++i) {
        rowsA[i] = A[i].data();
        rowsB[i] = B[i].data();
