        // First half‑step: compute B from A
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                rowsB[i][j] = coeff * (rowsA[i][j] +
                                       rowsA[i][j - 1] +
                                       rowsA[i][j + 1] +
                                       rowsA[i + 1][j] +
                                       rowsA[i - 1][j]);
