/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    /* The algorithm is inherently sequential in the outer dimension,
       but the inner loops over k can be vectorised for better
       utilisation of the SIMD units available on the target
       architecture.  The OpenMP compiler pragmas below do not
       introduce threading (the workload is serial) but enable
       automatic SIMD vectorisation with vector extensions. */
    for (int i = 0; i < n; ++i) {
        /* Off‑diagonal entries */
        for (int j = 0; j < i; ++j) {
            double *row_i = A[i].data();
            const double *row_j = A[j].data();
            double sum = row_i[j];
#pragma omp simd reduction(+:sum)
            for (int k = 0; k < j; ++k) {
                sum -= row_i[k] * row_j[k];
            }
            row_i[j] = sum / row_j[j];
        }

        /* Diagonal entry */
        double *row_i = A[i].data();
        double sum = row_i[i];
#pragma omp simd reduction(+:sum)
        for (int k = 0; k < i; ++k) {
            sum -= row_i[k] * row_i[k];
        }
        row_i[i] = std::sqrt(sum);
    }
}
