/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {
    /* Acquire raw pointers for each row to avoid repeated bounds checks. */
    std::vector<double*> A_ptrs(n);
    std::vector<double*> B_ptrs(n);
    for (int i = 0; i < n; ++i) {
        A_ptrs[i] = A[i].data();
        B_ptrs[i] = B[i].data();
    }

    /* Parallelize the outer loop with static scheduling. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_acc  = 0.0;
        double y_acc    = 0.0;
        const double* Ai = A_ptrs[i];
        const double* Bi = B_ptrs[i];
        const double* X  = x.data();

        /* Inner loop unrolled by 4 for better instruction‑level parallelism. */
        int j = 0;
        for (; j <= n - 4; j += 4) {
            double xi0 = X[j];
            double xi1 = X[j + 1];
            double xi2 = X[j + 2];
            double xi3 = X[j + 3];

            tmp_acc += Ai[j] * xi0      + Ai[j + 1] * xi1
                     + Ai[j + 2] * xi2  + Ai[j + 3] * xi3;

            y_acc   += Bi[j] * xi0      + Bi[j + 1] * xi1
                     + Bi[j + 2] * xi2  + Bi[j + 3] * xi3;
        }

        /* Handle remaining elements. */
        for (; j < n; ++j) {
            tmp_acc += Ai[j] * X[j];
            y_acc   += Bi[j] * X[j];
        }

        /* Store the results. */
        tmp[i] = tmp_acc;
        y[i]   = alpha * tmp_acc + beta * y_acc;
    }
}
