/* Optimised kernel preserving exact behaviour */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& /*sum_unused*/)
{
    /* Parallelise the two outer loops (r and q). Each iteration is
       independent, so we can use a collapsed OpenMP loop. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            /* Local temporary array to avoid data hazards on the
               original `sum` vector and to give the compiler freedom
               to optimise the inner loop. */
            std::vector<double> local_sum(np, 0.0);

            /* Compute A[r][q][p] = Σ_s A[r][q][s] * C4[s][p] */
            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                const auto& a_row = A[r][q];
                for (int s = 0; s < np; ++s) {
                    acc += a_row[s] * C4[s][p];
                }
                local_sum[p] = acc;
            }

            /* Write the result back into A. */
            auto& a_row = A[r][q];
            for (int p = 0; p < np; ++p) {
                a_row[p] = local_sum[p];
            }
        }
    }
}
