/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {
    // 1st update: A += u1*v1^T + u2*v2^T
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double>& Ai = A[i];
        const double ui1 = u1[i], ui2 = u2[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // 2nd update: x += beta * A^T * y
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += A[j][i] * y[j];
        }
        xi += beta * sum;
        x[i] = xi;
    }

    // 3rd update: x += z
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    // 4th update: w += alpha * A * x
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        const std::vector<double>& Ai = A[i];
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += Ai[j] * x[j];
        }
        wi += alpha * sum;
        w[i] = wi;
    }
