```cpp
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
		     std::vector<std::vector<int>>& table) {

    // Inline match function, returns 1 for A-U or G-C pairs (encoded as 1+2=3, 2+1=3),
    // otherwise 0. Sequence is encoded 0=A, 1=U, 2=G, 3=C.
    auto match = [](int b1, int b2) -> int {
        return (b1 + b2 == 3) ? 1 : 0;
    };

    // Dynamic‑programming in increasing order of substring length.
    // Parallelise over the starting index i for each fixed length.
    #pragma omp parallel for schedule(static)
    for (int len = 2; len <= n; ++len) {       // len = j-i+1
        for (int i = 0; i + len - 1 < n; ++i) {
            int j = i + len - 1;

            int best = 0;

            // If the j-1 character is treated separately
            if (j - 1 >= 0)
                best = std::max(best, table[i][j-1]);

            // If the i+1 character is treated separately
            if (i + 1 < n)
                best = std::max(best, table[i+1][j]);

            // Pair i and j (if possible)
            if (j - 1 >= 0 && i + 1 < n) {
                if (i < j - 1)
                    best = std::max(best, table[i+1][j-1] + match(seq[i], seq[j]));
                else
                    best = std::max(best, table[i+1][j-1]);   // i+1 == j
            }

            // Partition the substring into two parts
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best, table[i][k] + table[k+1][j]);
            }

            table[i][j] = best;
        }
    }
}
