#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A)
{
    // Parallelize the outer loop (i).  Each iteration of the loop
    // writes only to row i, therefore there are no race conditions
    // between threads.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        // First part: compute the lower part of the LU matrix.
        for (int j = 0; j < i; ++j)
        {
            double* Aij = A[i].data() + j;          // pointer to A[i][j]
            double* Aik = A[i].data();              // pointer to start of row i
            const double* Akj = nullptr;            // will be set inside loop

            // Accumulate the dot product A[i][j] -= sum_k A[i][k]*A[k][j]
            // where k ranges from 0 to j-1.
            double val = *Aij;                      // current A[i][j]
            for (int k = 0; k < j; ++k)
            {
                val -= Aik[k] * (Akj = A[k].data() + j)[0];
            }

            // Division by diagonal element A[j][j].
            val /= A[j][j];
            *Aij = val;
        }

        // Second part: compute the upper part of the LU matrix.
        for (int j = i; j < n; ++j)
        {
            double* Aij = A[i].data() + j;  // pointer to A[i][j]
            const double* Aik = A[i].data(); // row i

            // Accumulate the dot product A[i][j] -= sum_k A[i][k]*A[k][j]
            double val = *Aij;
            for (int k = 0; k < i; ++k)
            {
                val -= Aik[k] * A[k][j];
            }
            *Aij = val;
        }
    }
}
```
