/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Caution: the vectors must be large enough and properly contiguous.
    // The algorithm itself does not modify the layout of the vectors.
    for (int k = 0; k < n; ++k) {
        double nrm = 0.0;

        // Compute ||A_k||
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            nrm += A[i][k] * A[i][k];
        }

        R[k][k] = std::sqrt(nrm);

        // Normalize the column to get Q_k
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        // Orthogonalize remaining columns
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;

            // Compute R[k][j] = dot(Q_k, A_j)
#pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            // Update A_j = A_j - Q_k * R[k][j]
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * R[k][j];
            }
        }
    }
}
