 * implementation. */
void kernel_durbin(int n, std::vector<double>& r, std::vector<double>& y) {
    // Use raw pointers to increase cache locality.
    const double* rptr = r.data();
          double* yptr = y.data();

    // Workspace array z[n] allocated once.
    double* z = static_cast<double*>(std::aligned_alloc(64, n * sizeof(double)));
    if (!z) throw std::bad_alloc();

    // Initialisation
    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double* rcur = rptr + k - 1;
        const double* ycur = yptr;
        int i = 0;
        // manual loop unrolling for 4x factor
        for (; i <= k - 4; i += 4) {
            sum += rcur[ - i]     * ycur[ i];
            sum += rcur[-(i+1)]   * ycur[ i+1];
            sum += rcur[-(i+2)]   * ycur[ i+2];
            sum += rcur[-(i+3)]   * ycur[ i+3];
        }
        for (; i < k; ++i) {
            sum += rcur[ - i] * ycur[ i];
        }

        // Update alpha
        alpha = -(rptr[k] + sum) / beta;

        // Compute z[i] = y[i] + alpha * y[k-i-1] for i = 0 .. k-1
        const double* yrev = yptr + k - 1;
        for (i = 0; i < k; ++i) {
            z[i] = ycur[i] + alpha * yrev[i];
        }

        // Copy z back to y
        std::memcpy(yptr, z, k * sizeof(double));

        // Store new alpha
        yptr[k] = alpha;
    }

    std::free(z);
}
