    std::vector<double*> row_ptr(n);
    for (int i = 0; i < n; ++i) row_ptr[i] = A[i].data();

    /* ----------------- Doolittle LU decomposition --------------- */
    for (int i = 0; i < n; ++i) {
        double* Ai = row_ptr[i];

        // Compute L elements (sub-diagonal)
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
            double* Ak = row_ptr[i];
            double* Akj = row_ptr[j];
            // inner dot product
            for (int k = 0; k < j; ++k)
                w -= Ak[k] * Akj[k];
            Ai[j] = w / Akj[j];
        }

        // Compute U elements (diagonal and super-diagonal)
        // Parallelise only the independent part of this loop
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
            double* Ak = row_ptr[i];
            double* Akj = row_ptr[j];
            for (int k = 0; k < i; ++k)
                w -= Ak[k] * Akj[k];
            Ai[j] = w;
        }
    }

    /* ----------------- Forward substitution  y = L \ b ------------- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        double* Ai = row_ptr[i];
        for (int j = 0; j < i; ++j)
            w -= Ai[j] * y[j];
        y[i] = w;
    }

    /* ----------------- Backward substitution  x = U \ y ------------- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        double* Ai = row_ptr[i];
        for (int j = i + 1; j < n; ++j)
            w -= Ai[j] * x[j];
