                for (int jj2 = jj; jj2 < j_max; ++jj2) {
                    double sum = 0.0;
                    double* Brow_jj = Brow + jj2;
                    for (int k = 0; k < nk; ++k) {
                        sum += row_ptr(A, ii2)[k] * Brow_jj[k * nj];
                    }
                    Erow[jj2] = sum;
                }
            }
        }
    }

    /*--------------------------------------------------------------------
     * 2) F = C * D   (nj x nl)
     *--------------------------------------------------------------------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < nj; ii += NB) {
        int i_max = std::min(ii + NB, nj);
        for (int jj = 0; jj < nl; jj += NB) {
            int j_max = std::min(jj + NB, nl);
            for (int ii2 = ii; ii2 < i_max; ++ii2) {
                double* Frow = row_ptr(F, ii2);
                double* Drow = row_ptr(D, 0); // D is (nm x nl)
                for (int jj2 = jj; jj2 < j_max; ++jj2) {
                    double sum = 0.0;
                    double* Drow_jj = Drow + jj2;
                    for (int k = 0; k < nm; ++k) {
                        sum += row_ptr(C, ii2)[k] * Drow_jj[k * nl];
                    }
                    Frow[jj2] = sum;
                }
            }
        }
    }

    /*--------------------------------------------------------------------
     * 3) G = E * F   (ni x nl)
     *--------------------------------------------------------------------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += NB) {
        int i_max = std::min(ii + NB, ni);
        for (int jj = 0; jj < nl; jj += NB) {
            int j_max = std::min(jj + NB, nl);
            for (int ii2 = ii; ii2 < i_max; ++ii2) {
                double* Grow = row_ptr(G, ii2);
                double* Erow = row_ptr(E, ii2); // (nj)
                for (int jj2 = jj; jj2 < j_max; ++jj2) {
                    double sum = 0.0;
                    double* Fcol = row_ptr(F, 0); // F is (nj x nl)
                    for (int k = 0; k < nj; ++k) {
                        sum += Erow[k] * Fcol[k * nl + jj2];
                    }
                    Grow[jj2] = sum;
                }
            }
        }
    }
