#include <vector>
#include <cstddef>
#include <omp.h>

/* Helper to convert std::vector<std::vector<double>>
 * into a flat 1‑D array view.  The input vector must have
 * rows of equal length; otherwise behaviour is undefined
 * (the original code also assumes this). */
inline double* row_ptr(std::vector<std::vector<double>>& v, std::size_t r) {
    return v[r].data();
}

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {
    const double DX = 1.0 / static_cast<double>(n);
    const double DY = 1.0 / static_cast<double>(n);
    const double DT = 1.0 / static_cast<double>(tsteps);
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    /* 1‑D aliasing for the two exchanged arrays
     * (p and q are overwritten in each phase, so
     * using separate arrays is safe). */
    double* p_ptr  = nullptr;
    double* q_ptr  = nullptr;

    for (int t = 1; t <= tsteps; ++t) {
        /* -------- first (vertical) sweep -------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* u_row = row_ptr(u, i);
            double* v_row = row_ptr(v, i);
            double* p_col = row_ptr(p, i);
            double* q_col = row_ptr(q, i);

            v_row[0] = 1.0;
            p_col[0] = 0.0;
            q_col[0] = v_row[0];

            /* forward sweep along j (inside the column) */
            for (int j = 1; j < n - 1; ++j) {
                double denom = a * p_col[j-1] + b;
                p_col[j] = -c / denom;
                denom = a * p_col[j-1] + b;
                q_col[j] = (-d * u_row[j-1] + (1.0 + 2.0 * d) * u_row[j]
                            - f * u_row[j+1] - a * q_col[j-1]) / denom;
            }

            v_row[n-1] = 1.0;

            /* backward sweep along j */
            for (int j = n-2; j >= 1; --j) {
                v_row[j] = p_col[j] * v_row[j+1] + q_col[j];
            }
        }

        /* -------- second (horizontal) sweep -------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* u_row = row_ptr(u, i);
            double* v_row = row_ptr(v, i-1);  // v[i-1] row
            double* vp_row = row_ptr(v, i+1); // v[i+1] row
            double* p_col = row_ptr(p, i);
            double* q_col = row_ptr(q, i);

            u_row[0] = 1.0;
            p_col[0] = 0.0;
            q_col[0] = u_row[0];

            /* forward sweep along j */
            for (int j = 1; j < n - 1; ++j) {
                double denom = d * p_col[j-1] + e;
                p_col[j] = -f / denom;
                denom = d * p_col[j-1] + e;
                q_col[j] = (-a * v_row[j] + (1.0 + 2.0 * a) * u_row[j]
                            - c * vp_row[j] - d * q_col[j-1]) / denom;
            }

            u_row[n-1] = 1.0;

            /* backward sweep along j */
            for (int j = n-2; j >= 1; --j) {
                u_row[j] = p_col[j] * u_row[j+1] + q_col[j];
            }
        }
    }
}
